#include<bits/stdc++.h>
#define LL long long
using namespace std;
const int N = 1e5+5;
const LL INF = 0x3f3f3f3f3f3f3f3f;
struct line{LL to,w[2];};
struct node{LL x,d;};struct Line{LL v,w;};
struct LINE{LL x,y,u,v;}ln[5*N];
bool operator < (const node &A,const node &B){return A.d>B.d;}
int n,m;bool is[N];set<int> st[2][N];LL dis[5][N];
priority_queue<node> q;vector<line> g[N];vector<Line> E[N];
void Dijkstra(int opt){
    for(int i=1;i<=n;i++)dis[opt][i]=INF,is[i]=0;
    dis[opt][n]=0;while(!q.empty())q.pop();q.push({n,0});
    while(!q.empty()){
        int u=q.top().x;q.pop();
        if(is[u])continue;is[u]=1;
        for(auto [v,w]:g[u]){
            if(dis[opt][u]+w[opt]>dis[opt][v])continue;
            if(dis[opt][u]+w[opt]==dis[opt][v])st[opt][v].insert(u);
            if(dis[opt][u]+w[opt]<dis[opt][v]){
                st[opt][v].clear();st[opt][v].insert(u);
                dis[opt][v]=dis[opt][u]+w[opt];q.push({v,dis[opt][v]});
            }
        }
    }
}
void CountAnswer(){
    for(int i=1;i<=n;i++)dis[2][i]=INF,is[i]=0;
    dis[2][1]=0;while(!q.empty())q.pop();q.push({1,0});
    while(!q.empty()){
        auto [u,d]=q.top();q.pop();
        if(is[u])continue;is[u]=1;
        for(auto [v,w]:E[u]){
            if(dis[2][v]<=dis[2][u]+w)continue;
            dis[2][v]=dis[2][u]+w;q.push({v,dis[2][v]});
        }
    }
}
int main(){
    //freopen("gpsduel.in","r",stdin);
    //freopen("gpsduel.out","w",stdout);
    cin>>n>>m;
    for(int i=1;i<=m;i++){
        cin>>ln[i].x>>ln[i].y>>ln[i].u>>ln[i].v;
        g[ln[i].y].push_back({ln[i].x,{ln[i].u,ln[i].v}});
    }
    Dijkstra(0);Dijkstra(1);
    for(int i=1;i<=m;i++){
        int cnt=0;
        if(dis[0][ln[i].y]+ln[i].u!=dis[0][ln[i].x])cnt++;
        if(dis[1][ln[i].y]+ln[i].v!=dis[1][ln[i].x])cnt++;
        E[ln[i].x].push_back({ln[i].y,cnt});
    }
    CountAnswer();cout<<dis[2][n]<<"\n";
    return 0;
}
